        const delta = new Delta().retain(6).delete(5); // Delete "World"
        const inverted = delta.invert(base);

        // Inverting a delete should restore the deleted content
        assert.equal(inverted.ops.length, 2);
        assert.equal(inverted.ops[0].retain, 6);
        assert.equal(inverted.ops[1].insert, 'World');
        done();
    });

    it('test quill-delta.prototype.invert - retain without attributes', function(done) {
        const base = new Delta().insert('Hello');
        const delta = new Delta().retain(5);
        const inverted = delta.invert(base);

        // Inverting a plain retain should return the same retain
        assert.equal(inverted.ops.length, 1);
        assert.equal(inverted.ops[0].retain, 5);
        assert.equal(inverted.ops[0].attributes, undefined);
        done();
    });

    it('test quill-delta.prototype.invert - retain with attributes', function(done) {
        const base = new Delta().insert('Hello', { bold: true });
        const delta = new Delta().retain(5, { italic: true });
        const inverted = delta.invert(base);

        // Inverting attribute changes should restore original attributes
        assert.equal(inverted.ops.length, 1);
        assert.equal(inverted.ops[0].retain, 5);
        assert.equal(inverted.ops[0].attributes.italic, null);
        assert.equal(inverted.ops[0].attributes.bold, true);
        done();
    });

    it('test quill-delta.prototype.invert - complex operations', function(done) {
        const base = new Delta()
            .insert('Hello ')
            .insert('World', { bold: true })
            .insert('!');

        const delta = new Delta()
            .retain(6) // Keep "Hello "
            .delete(5) // Delete "World"
            .insert('Universe', { italic: true }) // Insert "Universe"
            .retain(1); // Keep "!"

        const inverted = delta.invert(base);

        // Should have operations to undo the changes
        assert.equal(inverted.ops.length, 4);
        assert.equal(inverted.ops[0].retain, 6); // Retain "Hello "
        assert.equal(inverted.ops[1].insert, 'World'); // Restore deleted "World"
        assert.deepEqual(inverted.ops[1].attributes, { bold: true });
        assert.equal(inverted.ops[2].delete, 8); // Delete inserted "Universe"
        assert.equal(inverted.ops[3].retain, 1); // Retain "!"
        done();
    });

    it('test quill-delta.prototype.invert - empty delta', function(done) {
        const base = new Delta().insert('Hello');
        const delta = new Delta();
        const inverted = delta.invert(base);

        // Inverting an empty delta should return an empty delta
        assert.equal(inverted.ops.length, 0);
        done();
