        const delta = new Delta().retain(6).insert('Beautiful ');
        const inverted = delta.invert(base);
        const doubleInverted = inverted.invert(delta.compose(base));

        // Double inversion should approximate the original delta
        assert.equal(doubleInverted.ops.length, 2);
        assert.equal(doubleInverted.ops[0].retain, 6);
        assert.equal(doubleInverted.ops[1].insert, 'Beautiful ');
        done();
    });
